import{_ as o,C as c,o as a,c as u,a5 as l,b as e,w as n,a as i,E as r,a4 as t}from"./chunks/framework.gGRxziV4.js";const g=JSON.parse('{"title":"05 - Skills 系统：给\\"天才毕业生\\"配上行业经验","description":"","frontmatter":{},"headers":[],"relativePath":"08-ECC教程/05-Skills系统.md","filePath":"08-ECC教程/05-Skills系统.md","lastUpdated":null}'),b={name:"08-ECC教程/05-Skills系统.md"};function d(m,s,A,E,q,k){const p=c("Mermaid");return a(),u("div",null,[s[3]||(s[3]=l(`<h1 id="_05-skills-系统-给-天才毕业生-配上行业经验" tabindex="-1">05 - Skills 系统：给&quot;天才毕业生&quot;配上行业经验 <a class="header-anchor" href="#_05-skills-系统-给-天才毕业生-配上行业经验" aria-label="Permalink to &quot;05 - Skills 系统：给&quot;天才毕业生&quot;配上行业经验&quot;">​</a></h1><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>没有 Skills 的 AI 就像一个&quot;刚毕业的天才&quot;——聪明绝顶，但没经验。Skills 是前辈总结的经验教训，告诉 AI&quot;在我们这个行业/项目里，事情应该怎么做&quot;。</p><hr><h2 id="真实痛点-ai-聪明-但-不懂规矩" tabindex="-1">真实痛点：AI 聪明，但&quot;不懂规矩&quot; <a class="header-anchor" href="#真实痛点-ai-聪明-但-不懂规矩" aria-label="Permalink to &quot;真实痛点：AI 聪明，但&quot;不懂规矩&quot;&quot;">​</a></h2><p>你有没有遇到过这种情况？</p><blockquote><p>你：帮我写一个 API 接口。 AI：好的！[哗哗写完] 你：等等，我们项目用的是 RESTful 风格，你这个不是。 AI：好的，改成 RESTful。 你：还有，返回格式要统一，用 <code>{code, message, data}</code>。 AI：好的。 你：错误码要用枚举定义，不能写死数字。 AI：好的。 你：……还有日志，每个接口要记录请求参数和响应时间。 AI：好的…… 你：（已经纠正了 5 次）</p></blockquote><p>AI 的能力没问题，问题是：<strong>TA 不知道你们团队/项目的规矩。</strong></p><p>这些规矩从哪来？从经验中来——你们踩过的坑、总结的最佳实践、团队的约定。<strong>Skills 就是把这些经验&quot;封装&quot;起来告诉 AI 的方式。</strong></p><p>打个比方：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你请了一个顶级厨师来你家做饭。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>厨师技术一流——什么菜都会做。但问题是：</span></span>
<span class="line"><span>- 你家的灶是电磁炉，不是明火</span></span>
<span class="line"><span>- 你对花生过敏</span></span>
<span class="line"><span>- 你家调料只有酱油醋，没有蚝油</span></span>
<span class="line"><span>- 你口味偏清淡</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果你什么都不说 → 厨师可能做了一桌爆炒花生，一样都不能吃</span></span>
<span class="line"><span>如果你提前说清楚 → 厨师会调整所有做法，完美适配你家</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Skills = 提前说清楚的那些话</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><hr><h2 id="为什么用-markdown-定义-skill-而不是-json-yaml" tabindex="-1">为什么用 Markdown 定义 Skill？而不是 JSON/YAML <a class="header-anchor" href="#为什么用-markdown-定义-skill-而不是-json-yaml" aria-label="Permalink to &quot;为什么用 Markdown 定义 Skill？而不是 JSON/YAML&quot;">​</a></h2><p>这是 Skills 系统一个非常重要的设计决策。</p><p>你可能想：配置文件不都用 JSON 或 YAML 吗？为什么要用 Markdown？</p><p><strong>因为 Skill 的核心受众是&quot;人和 AI&quot;，不是&quot;机器&quot;。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>如果用 JSON 定义 Skill：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;name&quot;: &quot;tdd-workflow&quot;,</span></span>
<span class="line"><span>  &quot;steps&quot;: [&quot;write_test&quot;, &quot;implement&quot;, &quot;refactor&quot;],</span></span>
<span class="line"><span>  &quot;coverage&quot;: 80,</span></span>
<span class="line"><span>  &quot;rules&quot;: [&quot;no_skip_tests&quot;, &quot;red_green_refactor&quot;]</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ AI 能解析，但人看不出来&quot;为什么&quot;这样做</span></span>
<span class="line"><span>→ 你不知道&quot;写测试&quot;具体怎么写、有什么注意事项</span></span>
<span class="line"><span>→ 遇到边界情况不知道怎么处理</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>如果用 Markdown 定义 Skill：</span></span>
<span class="line"><span></span></span>
<span class="line"><span># TDD 工作流</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 核心理念</span></span>
<span class="line"><span>先写测试，再写代码。因为&quot;先写代码再补测试&quot;永远补不完。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 步骤</span></span>
<span class="line"><span>1. 先写一个失败的测试（RED）</span></span>
<span class="line"><span>2. 写最少的代码让它通过（GREEN）</span></span>
<span class="line"><span>3. 重构代码，保持测试通过（REFACTOR）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 注意事项</span></span>
<span class="line"><span>- 测试覆盖率不低于 80%</span></span>
<span class="line"><span>- 不要为了覆盖率写无意义的测试</span></span>
<span class="line"><span>- 遇到不确定的地方，先写测试用例来澄清需求</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 常见坑</span></span>
<span class="line"><span>- 不要跳过 RED 阶段直接写实现</span></span>
<span class="line"><span>- 不要在一个测试里验证太多东西</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ AI 完全能理解&quot;怎么做&quot;和&quot;为什么这样做&quot;</span></span>
<span class="line"><span>→ 人也能看懂，还能审核、修改</span></span>
<span class="line"><span>→ 遇到边界情况，AI 知道&quot;意图&quot;是什么，能灵活处理</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br></div></div><p><strong>Markdown 的好处：既能给人看，又能给 AI 看。</strong> 一份文件，两种读者，都懂。这就是为什么不用 JSON/YAML——那些格式是给机器解析参数的，而 Skill 的本质是&quot;指南&quot;，需要解释、示例、注意事项。</p>`,19)),(a(),e(t,null,{default:n(()=>[r(p,{id:"mermaid-49",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20JSON%5B%22JSON%2FYAML%5Cn%E7%BB%99%E6%9C%BA%E5%99%A8%E8%A7%A3%E6%9E%90%E5%8F%82%E6%95%B0%5Cn%E7%BB%93%E6%9E%84%E5%8C%96%E6%95%B0%E6%8D%AE%5Cn%E4%BD%86%E6%B2%A1%E6%9C%89%E8%A7%A3%E9%87%8A%22%5D%0A%20%20%20%20MD%5B%22Markdown%5Cn%E7%BB%99%E4%BA%BA%E5%92%8C%20AI%20%E7%9C%8B%5Cn%E6%9C%89%E8%A7%A3%E9%87%8A%E3%80%81%E7%A4%BA%E4%BE%8B%E3%80%81%E6%B3%A8%E6%84%8F%E4%BA%8B%E9%A1%B9%5Cn%E4%BA%BA%E5%92%8C%20AI%20%E9%83%BD%E8%83%BD%E8%AF%BB%E6%87%82%22%5D%0A%0A%20%20%20%20JSON%20-.-%3E%7C%22%E4%B8%8D%E9%80%82%E5%90%88%22%7C%20SKILL%5B%22Skill%20%E7%9A%84%E6%9C%AC%E8%B4%A8%5Cn%E6%98%AF%E4%B8%80%E4%BB%BD%E3%80%8C%E5%B7%A5%E4%BD%9C%E6%8C%87%E5%8D%97%E3%80%8D%22%5D%0A%20%20%20%20MD%20--%3E%7C%22%E5%AE%8C%E7%BE%8E%E5%8C%B9%E9%85%8D%22%7C%20SKILL%0A%0A%20%20%20%20style%20JSON%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20MD%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20SKILL%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A"})]),fallback:n(()=>[...s[0]||(s[0]=[i(" Loading... ",-1)])]),_:1})),s[4]||(s[4]=l(`<hr><h2 id="skills-的分类-按照使用场景分-不是随便分的" tabindex="-1">Skills 的分类：按照使用场景分，不是随便分的 <a class="header-anchor" href="#skills-的分类-按照使用场景分-不是随便分的" aria-label="Permalink to &quot;Skills 的分类：按照使用场景分，不是随便分的&quot;">​</a></h2><p>Skills 不是杂乱地堆在一起的，而是按照<strong>使用场景</strong>分类的。这个分类方式背后有清晰的逻辑：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Skills 分类体系</span></span>
<span class="line"><span>═══════════════</span></span>
<span class="line"><span></span></span>
<span class="line"><span>🔧 语言/框架类（解决&quot;用这个技术应该怎么写&quot;）</span></span>
<span class="line"><span>├── python-patterns    ← Python 项目的最佳实践</span></span>
<span class="line"><span>├── golang-patterns    ← Go 项目的最佳实践</span></span>
<span class="line"><span>├── rust-patterns      ← Rust 项目的最佳实践</span></span>
<span class="line"><span>├── typescript-patterns ← TS 项目的最佳实践</span></span>
<span class="line"><span>├── django-patterns    ← Django 框架的最佳实践</span></span>
<span class="line"><span>├── springboot-patterns ← Spring Boot 的最佳实践</span></span>
<span class="line"><span>└── ……共 30+ 个</span></span>
<span class="line"><span></span></span>
<span class="line"><span>🔄 工作流类（解决&quot;开发流程应该怎么走&quot;）</span></span>
<span class="line"><span>├── tdd-workflow        ← 测试驱动开发</span></span>
<span class="line"><span>├── verification-loop   ← 质量门禁</span></span>
<span class="line"><span>├── continuous-learning  ← 自动学习</span></span>
<span class="line"><span>├── eval-harness        ← 评估框架</span></span>
<span class="line"><span>└── autonomous-loops    ← 自主循环</span></span>
<span class="line"><span></span></span>
<span class="line"><span>🔒 安全类（解决&quot;怎么防止安全问题&quot;）</span></span>
<span class="line"><span>├── security-review     ← 通用安全审查</span></span>
<span class="line"><span>├── security-scan       ← 安全扫描</span></span>
<span class="line"><span>├── django-security     ← Django 专属安全</span></span>
<span class="line"><span>├── laravel-security    ← Laravel 专属安全</span></span>
<span class="line"><span>└── springboot-security ← Spring Boot 专属安全</span></span>
<span class="line"><span></span></span>
<span class="line"><span>💼 业务类（解决&quot;特定行业的专业知识&quot;）</span></span>
<span class="line"><span>├── market-research     ← 市场调研</span></span>
<span class="line"><span>├── deep-research       ← 深度研究</span></span>
<span class="line"><span>├── article-writing     ← 文章写作</span></span>
<span class="line"><span>├── content-engine      ← 内容引擎</span></span>
<span class="line"><span>└── investor-materials  ← 投资者材料</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br></div></div><p><strong>为什么要这样分？</strong> 因为使用场景不同，需要的&quot;经验&quot;完全不同：</p><ul><li>你在写 Python 代码 → 需要知道 Python 的最佳实践（语言类）</li><li>你在做团队协作 → 需要知道 TDD 流程怎么走（工作流类）</li><li>你在处理用户数据 → 需要知道安全怎么做（安全类）</li><li>你在做市场分析 → 需要知道调研方法论（业务类）</li></ul><p>每种场景都有不同的&quot;坑&quot;，需要不同的&quot;经验&quot;来避免。</p><hr><h2 id="每个-skill-长什么样" tabindex="-1">每个 Skill 长什么样？ <a class="header-anchor" href="#每个-skill-长什么样" aria-label="Permalink to &quot;每个 Skill 长什么样？&quot;">​</a></h2><p>一个 Skill 就是一个文件夹，里面放着&quot;工作指南&quot;：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>skills/</span></span>
<span class="line"><span>├── tdd-workflow/</span></span>
<span class="line"><span>│   ├── SKILL.md          ← 核心：工作指南（给人和 AI 看的）</span></span>
<span class="line"><span>│   └── scripts/          ← 可能有一些辅助脚本</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── verification-loop/</span></span>
<span class="line"><span>│   └── SKILL.md</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── python-patterns/</span></span>
<span class="line"><span>│   └── SKILL.md</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p><strong>SKILL.md 是灵魂。</strong> 它用自然语言写成，包含：</p><ul><li>这个 Skill 解决什么问题</li><li>具体步骤是什么</li><li>有什么注意事项</li><li>常见错误有哪些</li><li>用实际示例说明</li></ul><hr><h2 id="skills-和-commands-的区别" tabindex="-1">Skills 和 Commands 的区别 <a class="header-anchor" href="#skills-和-commands-的区别" aria-label="Permalink to &quot;Skills 和 Commands 的区别&quot;">​</a></h2><p>学到这里你可能会混淆：Skills 和上一章的 Commands 有什么不同？</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Commands（命令）</span></span>
<span class="line"><span>───────────────</span></span>
<span class="line"><span>你主动说的话</span></span>
<span class="line"><span>&quot;/tdd 写一个排序函数&quot;</span></span>
<span class="line"><span>你触发，AI 执行</span></span>
<span class="line"><span>像&quot;你点了一道菜&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Skills（技能）</span></span>
<span class="line"><span>───────────────</span></span>
<span class="line"><span>AI 脑子里的工作手册</span></span>
<span class="line"><span>&quot;写测试时你应该这样写……&quot;</span></span>
<span class="line"><span>自动加载，默默生效</span></span>
<span class="line"><span>像&quot;厨房的食品安全规定&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p><strong>两者配合使用：</strong></p><blockquote><p>你输入 <code>/tdd 写一个排序函数</code> ← 这是 Command（你说的话） AI 加载 <code>tdd-workflow</code> Skill ← 这是 Skill（AI 遵守的规矩） AI 按照 Skill 里的流程工作 ← 先写测试 → 再实现 → 再重构 测试覆盖率要 80%+ ← 这是 Skill 里的规则</p></blockquote>`,19)),(a(),e(t,null,{default:n(()=>[r(p,{id:"mermaid-140",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20USER%5B%22%F0%9F%91%A4%20%E7%94%A8%E6%88%B7%E8%BE%93%E5%85%A5%20%2Ftdd%20%E5%86%99%E6%8E%92%E5%BA%8F%E5%87%BD%E6%95%B0%22%5D%20--%3E%20CMD%5B%22%F0%9F%93%8B%20Command%20%E5%B1%82%5Cn%2Ftdd%20%E5%91%BD%E4%BB%A4%E8%A2%AB%E8%A7%A6%E5%8F%91%22%5D%0A%20%20%20%20CMD%20--%3E%20SKILL%5B%22%F0%9F%93%96%20Skill%20%E5%B1%82%5Cntdd-workflow%20%E8%A2%AB%E5%8A%A0%E8%BD%BD%5Cn%E8%A7%84%E5%AE%9A%E4%BA%86%E5%B7%A5%E4%BD%9C%E6%B5%81%E7%A8%8B%22%5D%0A%20%20%20%20SKILL%20--%3E%20WORK%5B%22%F0%9F%A4%96%20AI%20%E6%8C%89%20Skill%20%E6%B5%81%E7%A8%8B%E5%B7%A5%E4%BD%9C%5CnRED%20%E2%86%92%20GREEN%20%E2%86%92%20REFACTOR%22%5D%0A%0A%20%20%20%20style%20USER%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20CMD%20fill%3A%23ff9800%2Ccolor%3A%23fff%0A%20%20%20%20style%20SKILL%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20WORK%20fill%3A%231a237e%2Ccolor%3A%23fff%0A"})]),fallback:n(()=>[...s[1]||(s[1]=[i(" Loading... ",-1)])]),_:1})),s[5]||(s[5]=l(`<hr><h2 id="skill-进化-好的-skill-不是一次写成的" tabindex="-1">Skill 进化：好的 Skill 不是一次写成的 <a class="header-anchor" href="#skill-进化-好的-skill-不是一次写成的" aria-label="Permalink to &quot;Skill 进化：好的 Skill 不是一次写成的&quot;">​</a></h2><p>这是 Skills 系统最有趣的设计之一：<strong>Skill 可以进化。</strong></p><p>什么意思？一开始你写了一个 Skill，可能不完美。在使用过程中，你会发现：</p><ul><li>&quot;这个步骤缺了&quot;</li><li>&quot;这个注意事项应该加上&quot;</li><li>&quot;这个规则太严了，改宽松一点&quot;</li></ul><p>Skills 系统支持这种迭代——你可以随时修改 SKILL.md，AI 下次就会按照新版本工作。</p><p><strong>为什么需要进化？因为经验是积累出来的。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Skill 的生命周期：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  v1.0 → 团队总结了基础最佳实践</span></span>
<span class="line"><span>  v1.1 → 用了两个月，发现漏了&quot;错误处理&quot;的规范，补上</span></span>
<span class="line"><span>  v1.2 → 新人犯了一个常见错误，加到&quot;常见坑&quot;里</span></span>
<span class="line"><span>  v2.0 → 换了框架，整个 Skill 大改</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>打个比方：一本菜谱不是出版了就永远不变。厨师用着用着，会加新菜、改做法、标注&quot;这个菜新手容易翻车&quot;。Skill 也是一样。</p>`,9)),(a(),e(t,null,{default:n(()=>[r(p,{id:"mermaid-178",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20V1%5B%22v1.0%5Cn%E5%88%9D%E5%A7%8B%E7%89%88%E6%9C%AC%5Cn%E5%9F%BA%E7%A1%80%E8%A7%84%E5%88%99%22%5D%20--%3E%20V2%5B%22v1.1%5Cn%E8%A1%A5%E5%85%85%E9%81%97%E6%BC%8F%5Cn%E5%8A%A0%E6%B3%A8%E6%84%8F%E4%BA%8B%E9%A1%B9%22%5D%0A%20%20%20%20V2%20--%3E%20V3%5B%22v1.2%5Cn%E5%8A%A0%E5%B8%B8%E8%A7%81%E5%9D%91%5Cn%E6%96%B0%E4%BA%BA%E5%8F%8D%E9%A6%88%22%5D%0A%20%20%20%20V3%20--%3E%20V4%5B%22v2.0%5Cn%E6%A1%86%E6%9E%B6%E5%8D%87%E7%BA%A7%5Cn%E5%A4%A7%E6%94%B9%E7%89%88%22%5D%0A%0A%20%20%20%20style%20V1%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20V2%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20V3%20fill%3A%23ff9800%2Ccolor%3A%23fff%0A%20%20%20%20style%20V4%20fill%3A%23ab47bc%2Ccolor%3A%23fff%0A"})]),fallback:n(()=>[...s[2]||(s[2]=[i(" Loading... ",-1)])]),_:1})),s[6]||(s[6]=l(`<hr><h2 id="你该怎么使用-skills" tabindex="-1">你该怎么使用 Skills？ <a class="header-anchor" href="#你该怎么使用-skills" aria-label="Permalink to &quot;你该怎么使用 Skills？&quot;">​</a></h2><p><strong>好消息：大部分时候，你什么都不用做。</strong></p><p>Skills 有两种激活方式：</p><p><strong>方式 1：自动激活（AI 自己判断）</strong></p><p>你正常跟 AI 对话，AI 自动判断：</p><ul><li>&quot;用户在写 Python 代码&quot; → 自动加载 <code>python-patterns</code></li><li>&quot;用户在写测试&quot; → 自动加载 <code>tdd-workflow</code></li><li>&quot;用户在处理用户数据&quot; → 自动加载 <code>security-review</code></li></ul><p>你不需要说&quot;请激活 xxx Skill&quot;。</p><p><strong>方式 2：通过 Commands 间接触发</strong></p><p>你输入 <code>/tdd</code> → 系统自动加载 <code>tdd-workflow</code> Skill 你输入 <code>/verify</code> → 系统自动加载 <code>verification-loop</code> Skill</p><p><strong>你真正需要知道的就一件事：</strong> Skills 在后台默默工作，确保 AI 的行为符合最佳实践。你享受结果就好。</p><hr><h2 id="skills-和-rules-的区别" tabindex="-1">Skills 和 Rules 的区别 <a class="header-anchor" href="#skills-和-rules-的区别" aria-label="Permalink to &quot;Skills 和 Rules 的区别&quot;">​</a></h2><p>你可能还会问：Skills 和下一章的 Rules 又有什么不同？</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Rules（规则）          Skills（技能）</span></span>
<span class="line"><span>══════════           ════════════</span></span>
<span class="line"><span>强制执行的&quot;法律&quot;       建议性的&quot;方法论&quot;</span></span>
<span class="line"><span>必须遵守               灵活应用</span></span>
<span class="line"><span>全局生效               按场景加载</span></span>
<span class="line"><span>&quot;文件不能超过 800 行&quot;   &quot;TDD 流程应该怎么走&quot;</span></span>
<span class="line"><span>像交通法规             像驾驶技巧</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>Rules 是底线，不能违反。Skills 是最佳实践，告诉你&quot;更好的做法&quot;。两者配合，既保证了下限，又提升了上限。</p><hr><h2 id="好处和代价" tabindex="-1">好处和代价 <a class="header-anchor" href="#好处和代价" aria-label="Permalink to &quot;好处和代价&quot;">​</a></h2><p><strong>好处：</strong></p><ul><li>🧠 AI 不用每次重新&quot;学规矩&quot;，规则一次写好自动生效</li><li>📝 用 Markdown 写，人和 AI 都能看懂</li><li>🔄 可以迭代进化，越用越好</li><li>🎯 按场景分类，精准匹配需求</li><li>🤝 团队共享：一个 Skill 写好，全团队的 AI 都受益</li></ul><p><strong>代价：</strong></p><ul><li>✍️ 好的 Skill 需要花时间打磨（不过可以从社区借鉴）</li><li>📦 Skill 太多可能导致加载时间变长</li><li>⚖️ 不同 Skill 之间可能有冲突，需要合理组织</li></ul><hr><h2 id="对你自己的项目的启发" tabindex="-1">对你自己的项目的启发 <a class="header-anchor" href="#对你自己的项目的启发" aria-label="Permalink to &quot;对你自己的项目的启发&quot;">​</a></h2><ol><li><strong>经验应该被固化</strong> — 你和团队踩过的坑、总结的最佳实践，不应该只存在于&quot;脑子里&quot;，应该写下来让 AI 也学会</li><li><strong>Markdown 是给&quot;人+AI&quot;写的格式</strong> — 如果你的配置文件既需要人看又需要机器读，考虑用 Markdown 而不是 JSON</li><li><strong>分类要按场景来</strong> — 不要按技术栈分类（&quot;React 的&quot;、&quot;Vue 的&quot;），要按问题分类（&quot;写代码时&quot;、&quot;测试时&quot;、&quot;部署时&quot;）</li><li><strong>好文档是迭代出来的</strong> — 不要追求第一版就完美，先用起来，从实践中改进</li></ol><blockquote><p>💡 <strong>下一步</strong>：去看看你项目里有没有 <code>skills/</code> 目录。打开一个 SKILL.md 看看，你会发现里面就是普通的中文/英文——没有代码，没有配置，就是一份&quot;工作指南&quot;。</p></blockquote>`,26))])}const S=o(b,[["render",d]]);export{g as __pageData,S as default};
